blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie uporządkujesz użycie <strong>no</strong>, <strong>none</strong>, <strong>neither</strong> i <strong>either</strong>. Zobaczysz, kiedy stoją przed rzeczownikiem, kiedy występują samodzielnie i jak poprawnie mówić o dwóch opcjach.",
    "rules": [
        {
            "label": "No",
            "color": "rose",
            "text": "<strong>No</strong> stawiamy <strong>przed rzeczownikiem</strong>, gdy chcemy powiedzieć, że czegoś nie ma.",
            "example": "No students came. / I have no money."
        },
        {
            "label": "None",
            "color": "purple",
            "text": "<strong>None</strong> działa <strong>samodzielnie</strong> albo w konstrukcji <strong>none of + determiner + noun</strong>.",
            "example": "None came. / None of the students came."
        },
        {
            "label": "Neither / either",
            "color": "blue",
            "text": "<strong>Neither</strong> oznacza „żadna z dwóch”, a <strong>either</strong> oznacza „dowolna z dwóch”.",
            "example": "Neither answer is correct. / Either answer is fine."
        }
    ]
}

{
    "title": "1. Szybki przegląd",
    "intro": "Te cztery słowa pełnią różne funkcje w zdaniu:",
    "items": [
        {
            "label": "No",
            "title": "przed rzeczownikiem",
            "subtitle": "no money, no problem, no students"
        },
        {
            "label": "None",
            "title": "samodzielnie lub z of",
            "subtitle": "None came. / None of my friends replied."
        },
        {
            "label": "Neither / either",
            "title": "tylko dwie opcje",
            "subtitle": "Neither door is open. / Either door will do."
        }
    ]
}

{
    "title": "2. No: brak przed rzeczownikiem",
    "sections": [
        {
            "label": "Przed rzeczownikiem",
            "color": "rose",
            "description": "<strong>No</strong> jest określnikiem, więc stoi <strong>bezpośrednio przed rzeczownikiem</strong>.",
            "examples": [
                {
                    "en": "I have no money.",
                    "ua": "Nie mam pieniędzy."
                },
                {
                    "en": "There are no mistakes in this sentence.",
                    "ua": "W tym zdaniu nie ma błędów."
                },
                {
                    "en": "No students were absent today.",
                    "ua": "Dzisiaj żaden uczeń nie był nieobecny."
                }
            ]
        },
        {
            "label": "Policzalne / niepoliczalne",
            "color": "amber",
            "description": "<strong>No</strong> łączy się zarówno z rzeczownikami <strong>policzalnymi</strong>, jak i <strong>niepoliczalnymi</strong>.",
            "examples": [
                {
                    "en": "no books",
                    "ua": "żadne książki / brak książek"
                },
                {
                    "en": "no water",
                    "ua": "brak wody"
                },
                {
                    "en": "no time",
                    "ua": "brak czasu"
                }
            ]
        },
        {
            "label": "No a not any",
            "color": "sky",
            "description": "<strong>No</strong> i <strong>not any</strong> często znaczą to samo, ale <strong>no</strong> brzmi krócej i mocniej.",
            "examples": [
                {
                    "en": "I have no money. = I don't have any money.",
                    "ua": "Oba zdania znaczą: „Nie mam pieniędzy”."
                },
                {
                    "en": "There were no tickets left. = There weren't any tickets left.",
                    "ua": "Obie wersje są poprawne."
                }
            ],
            "note": "📌 <strong>No</strong> jest częste w krótkich, zdecydowanych komunikatach."
        }
    ]
}

{
    "title": "3. None: samodzielnie albo z of",
    "sections": [
        {
            "label": "Bez rzeczownika",
            "color": "purple",
            "description": "<strong>None</strong> może wystąpić <strong>samodzielnie</strong>, gdy rzeczownik jest już znany z kontekstu.",
            "examples": [
                {
                    "en": "How many students came? — None.",
                    "ua": "Ilu uczniów przyszło? — Żaden."
                },
                {
                    "en": "I wanted some coffee, but there was none.",
                    "ua": "Chciałem kawy, ale jej nie było."
                },
                {
                    "en": "None were ready.",
                    "ua": "Nikt nie był gotowy."
                }
            ]
        },
        {
            "label": "None of + determiner + noun",
            "color": "rose",
            "description": "Używamy <strong>none of</strong> przed rzeczownikiem z określnikiem, np. <strong>the, my, these</strong>.",
            "examples": [
                {
                    "en": "None of the students passed.",
                    "ua": "Żaden z uczniów nie zdał."
                },
                {
                    "en": "None of my friends came.",
                    "ua": "Żaden z moich znajomych nie przyszedł."
                },
                {
                    "en": "None of this is true.",
                    "ua": "Nic z tego nie jest prawdą."
                }
            ]
        },
        {
            "label": "No i none: różnica",
            "color": "sky",
            "description": "Najważniejsza różnica dotyczy pozycji w zdaniu: <strong>no</strong> stoi przed rzeczownikiem, a <strong>none</strong> go zastępuje.",
            "examples": [
                {
                    "en": "No students came.",
                    "ua": "No stoi przed rzeczownikiem students."
                },
                {
                    "en": "None came.",
                    "ua": "None występuje samodzielnie."
                },
                {
                    "en": "None of the students came.",
                    "ua": "To pełna konstrukcja z of."
                }
            ],
            "note": "📌 Nie mówimy <strong>none students</strong>."
        }
    ]
}

{
    "title": "4. Neither: żadna z dwóch",
    "sections": [
        {
            "label": "Dwie opcje",
            "color": "blue",
            "description": "<strong>Neither</strong> oznacza, że <strong>żadna z dwóch możliwości</strong> nie jest poprawna lub nie pasuje.",
            "examples": [
                {
                    "en": "Neither option is good.",
                    "ua": "Żadna z dwóch opcji nie jest dobra."
                },
                {
                    "en": "Neither answer is correct.",
                    "ua": "Żadna z dwóch odpowiedzi nie jest poprawna."
                },
                {
                    "en": "Neither team won.",
                    "ua": "Żadna z dwóch drużyn nie wygrała."
                }
            ]
        },
        {
            "label": "Neither of + determiner + noun",
            "color": "purple",
            "description": "Często używamy konstrukcji <strong>neither of</strong> z rzeczownikiem lub zaimkiem odnoszącym się do dwóch elementów.",
            "examples": [
                {
                    "en": "Neither of the books is interesting.",
                    "ua": "Żadna z tych dwóch książek nie jest interesująca."
                },
                {
                    "en": "Neither of them came.",
                    "ua": "Żadne z nich nie przyszło."
                },
                {
                    "en": "Neither of my parents speaks English.",
                    "ua": "Żadne z moich rodziców nie mówi po angielsku."
                }
            ]
        },
        {
            "label": "Neither ... nor ...",
            "color": "rose",
            "description": "Konstrukcja <strong>neither ... nor ...</strong> oznacza „ani ... ani ...”.",
            "examples": [
                {
                    "en": "Neither John nor Mary came.",
                    "ua": "Ani John, ani Mary nie przyszli."
                },
                {
                    "en": "I like neither tea nor coffee.",
                    "ua": "Nie lubię ani herbaty, ani kawy."
                },
                {
                    "en": "It was neither hot nor cold.",
                    "ua": "Nie było ani gorąco, ani zimno."
                }
            ],
            "note": "⚠️ <strong>Neither</strong> ma już znaczenie przeczące, więc nie dodajemy tu drugiego <strong>not</strong>."
        }
    ]
}

{
    "title": "5. Either: dowolna z dwóch",
    "sections": [
        {
            "label": "Dowolna z dwóch",
            "color": "emerald",
            "description": "<strong>Either</strong> oznacza, że <strong>każda z dwóch możliwości</strong> jest możliwa lub akceptowalna.",
            "examples": [
                {
                    "en": "Either option is fine.",
                    "ua": "Każda z dwóch opcji jest w porządku."
                },
                {
                    "en": "You can take either book.",
                    "ua": "Możesz wziąć dowolną z tych dwóch książek."
                },
                {
                    "en": "Either route will get us there.",
                    "ua": "Każda z dwóch tras nas tam doprowadzi."
                }
            ]
        },
        {
            "label": "Either of + determiner + noun",
            "color": "sky",
            "description": "Używamy też konstrukcji <strong>either of</strong>, gdy mówimy o dwóch konkretnych osobach lub rzeczach.",
            "examples": [
                {
                    "en": "Either of the books is useful.",
                    "ua": "Każda z tych dwóch książek jest przydatna."
                },
                {
                    "en": "Either of them can help you.",
                    "ua": "Każde z nich może ci pomóc."
                },
                {
                    "en": "You can choose either of the two plans.",
                    "ua": "Możesz wybrać dowolny z tych dwóch planów."
                }
            ]
        },
        {
            "label": "Either ... or ...",
            "color": "amber",
            "description": "Konstrukcja <strong>either ... or ...</strong> oznacza „albo ... albo ...”.",
            "examples": [
                {
                    "en": "You can have either tea or coffee.",
                    "ua": "Możesz wybrać herbatę albo kawę."
                },
                {
                    "en": "Either John or Mary will come.",
                    "ua": "Przyjdzie albo John, albo Mary."
                },
                {
                    "en": "We'll go either today or tomorrow.",
                    "ua": "Pójdziemy albo dziś, albo jutro."
                }
            ]
        }
    ]
}

{
    "title": "6. Neither i either: najważniejsza różnica",
    "sections": [
        {
            "label": "Znaczenie podstawowe",
            "color": "purple",
            "description": "<strong>Neither</strong> jest przeczące, a <strong>either</strong> jest pozytywne. Oba słowa odnoszą się do <strong>dwóch</strong> opcji.",
            "examples": [
                {
                    "en": "Neither book is useful.",
                    "ua": "Żadna z dwóch książek nie jest przydatna."
                },
                {
                    "en": "Either book is useful.",
                    "ua": "Każda z dwóch książek jest przydatna."
                }
            ]
        },
        {
            "label": "Either po przeczeniu",
            "color": "rose",
            "description": "Na końcu zdania <strong>either</strong> może znaczyć „też nie”.",
            "examples": [
                {
                    "en": "I don't like coffee. — I don't either.",
                    "ua": "Nie lubię kawy. — Ja też nie."
                },
                {
                    "en": "She can't come. — He can't either.",
                    "ua": "Ona nie może przyjść. — On też nie może."
                }
            ],
            "note": "📌 To inne użycie niż <strong>either</strong> w znaczeniu „dowolny z dwóch”."
        },
        {
            "label": "Porównanie w zdaniach",
            "color": "sky",
            "description": "Porównaj zdania przeczące i pozytywne:",
            "examples": [
                {
                    "en": "Neither of them called.",
                    "ua": "Żadne z nich nie zadzwoniło."
                },
                {
                    "en": "Either of them can help.",
                    "ua": "Każde z nich może pomóc."
                },
                {
                    "en": "Neither answer is correct.",
                    "ua": "Żadna odpowiedź nie jest poprawna."
                },
                {
                    "en": "Either answer is acceptable.",
                    "ua": "Każda odpowiedź jest akceptowalna."
                }
            ]
        }
    ]
}

{
    "title": "7. Zgodność z czasownikiem",
    "sections": [
        {
            "label": "No + noun",
            "color": "amber",
            "description": "Czasownik zgadza się z rzeczownikiem, który stoi po <strong>no</strong>.",
            "examples": [
                {
                    "en": "No student is absent.",
                    "ua": "Rzeczownik jest w liczbie pojedynczej, więc czasownik też."
                },
                {
                    "en": "No students are absent.",
                    "ua": "Rzeczownik jest w liczbie mnogiej, więc czasownik też."
                }
            ]
        },
        {
            "label": "None of",
            "color": "sky",
            "description": "Po <strong>none of</strong> spotkasz zarówno liczbę pojedynczą, jak i mnogą. W codziennej angielszczyźnie liczba mnoga jest bardzo częsta.",
            "examples": [
                {
                    "en": "None of the information is useful.",
                    "ua": "Z rzeczownikiem niepoliczalnym używamy liczby pojedynczej."
                },
                {
                    "en": "None of the students are ready.",
                    "ua": "W mowie codziennej liczba mnoga brzmi naturalnie."
                },
                {
                    "en": "None of the answers is / are correct.",
                    "ua": "Obie wersje są spotykane, zależnie od stylu."
                }
            ]
        },
        {
            "label": "Neither i either",
            "color": "purple",
            "description": "<strong>Neither</strong> i <strong>either</strong> najczęściej łączą się z czasownikiem w <strong>liczbie pojedynczej</strong>.",
            "examples": [
                {
                    "en": "Neither option works.",
                    "ua": "Standardowo używamy liczby pojedynczej."
                },
                {
                    "en": "Either answer is fine.",
                    "ua": "To samo dotyczy either."
                }
            ],
            "note": "📌 W mniej formalnym użyciu możesz czasem usłyszeć liczbę mnogą, ale norma szkolna to liczba pojedyncza."
        }
    ]
}

{
    "title": "8. Tabela porównawcza",
    "intro": "Najważniejsze różnice między <strong>no</strong>, <strong>none</strong>, <strong>neither</strong> i <strong>either</strong>:",
    "rows": [
        {
            "en": "No",
            "ua": "określnik przed rzeczownikiem",
            "note": "no money, no students"
        },
        {
            "en": "None",
            "ua": "zaimek / none of",
            "note": "None came. / none of them"
        },
        {
            "en": "Neither",
            "ua": "żadna z dwóch",
            "note": "neither option, neither of them"
        },
        {
            "en": "Either",
            "ua": "dowolna z dwóch",
            "note": "either option, either of them"
        },
        {
            "en": "Neither ... nor ...",
            "ua": "ani ... ani ...",
            "note": "Neither tea nor coffee"
        },
        {
            "en": "Either ... or ...",
            "ua": "albo ... albo ...",
            "note": "Either tea or coffee"
        }
    ],
    "warning": "📌 <strong>Neither</strong> ma już znaczenie przeczące, więc nie łączymy go z dodatkowym <strong>not</strong> w tym samym sensie."
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Użycie none bez of przed rzeczownikiem.",
            "wrong": "None students came.",
            "right": "✅ No students came. / None of the students came."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Podwójne przeczenie z neither.",
            "wrong": "Neither of them didn't come.",
            "right": "✅ Neither of them came."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Neither przy więcej niż dwóch opcjach.",
            "wrong": "Neither of the three answers is correct.",
            "right": "✅ None of the three answers is correct."
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Mylenie either i neither.",
            "wrong": "Either option works. (gdy żadna nie działa)",
            "right": "✅ Neither option works."
        }
    ]
}

{
    "title": "11. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawne słowo",
    "select_intro": "W każdym zdaniu wybierz <strong>no</strong>, <strong>none</strong>, <strong>neither</strong> albo <strong>either</strong>.",
    "selects": [
        {
            "label": "I have ___ time today. (no / none)",
            "prompt": "Które słowo pasuje?"
        },
        {
            "label": "How many students were absent?",
            "prompt": "Które słowo pasuje?"
        },
        {
            "label": "___ of the two answers is correct. (Neither / Either)",
            "prompt": "Które słowo pasuje?"
        },
        {
            "label": "You can take ___ book. (neither / either)",
            "prompt": "Które słowo pasuje?"
        }
    ],
    "options": [
        "Pierwsza opcja",
        "Druga opcja"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij zdania",
    "input_intro": "Wpisz poprawne słowo: <strong>no</strong>, <strong>none</strong>, <strong>neither</strong> albo <strong>either</strong>.",
    "inputs": [
        {
            "before": "___ of the students passed the exam.",
            "after": " →"
        },
        {
            "before": "There is ___ milk left.",
            "after": " →"
        },
        {
            "before": "___ of them can help you. (dwie osoby)",
            "after": " →"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd w zdaniu.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Neither of them didn't call.",
            "example_target": "Neither of them called."
        },
        {
            "original": "1. None students came.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. Neither of the three answers is correct.",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "No / none / neither / either",
            "current": true
        },
        {
            "label": "Quantifiers",
            "current": false
        },
        {
            "label": "Partitives",
            "current": false
        },
        {
            "label": "Zero article",
            "current": false
        }
    ]
}
